def main():
    def modInverse(a, m):
        m0, x0, x1 = (m, 0, 1)
        if m == 1:
            return 0
        while a > 1:
            q = a // m
            m, a = (a % m, m)
            x0, x1 = (x1 - q * x0, x0)
        return x1 + m0 if x1 < 0 else x1

    def findMinX(num, rem, k):
        N = 1
        for i in range(k):
            N *= num[i]
        result = 0
        for i in range(k):
            n_i = N // num[i]
            inv_i = modInverse(n_i, num[i])
            result += rem[i] * n_i * inv_i
        return result % N

    num = [3, 4, 5]

    rem = [2, 3, 1]

    k = len(num)

    print('x is', findMinX(num, rem, k))

if __name__ == "__main__":
    main()

